// src/App.js
import React, { useState, useEffect, useCallback, Suspense } from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { useAuth } from './context/AuthContext';
import { ThemeProvider, useTheme } from './context/ThemeContext';
import { CartProvider } from './context/CartContext';
import { WishlistProvider } from './context/WishlistContext'; // Fixed import name

// Layout Components
import Navbar from './components/Navbar/Navbar';
import Sidebar from './components/Sidebar/Sidebar';
import ChatWidget from './components/Chat/ChatWidget';

// Page Components (Lazy loaded for performance)
const HomePage = React.lazy(() => import('./pages/HomePage'));
const ProductsPage = React.lazy(() => import('./pages/ProductsPage'));
const ProductDetailPage = React.lazy(() => import('./pages/ProductDetailPage'));
const CartPage = React.lazy(() => import('./pages/CartPage'));
const CheckoutPage = React.lazy(() => import('./pages/CheckoutPage'));
const OrdersPage = React.lazy(() => import('./pages/OrdersPage'));
const OrderDetailPage = React.lazy(() => import('./pages/OrderDetailPage'));
const TrackingPage = React.lazy(() => import('./pages/TrackingPage'));
const AccountPage = React.lazy(() => import('./pages/AccountPage'));
const SettingsPage = React.lazy(() => import('./pages/SettingsPage'));
const LoginPage = React.lazy(() => import('./pages/LoginPage'));
const RegisterPage = React.lazy(() => import('./pages/RegisterPage'));
const NotificationsPage = React.lazy(() => import('./pages/NotificationsPage')); // Fixed naming
const OffersPage = React.lazy(() => import('./pages/OffersPage')); // Fixed naming
const PriceDropProductPage = React.lazy(() => import('./pages/PriceDropProductPage'));
const WalletPage = React.lazy(() => import('./components/wallet/WalletPage'));
const WishlistPage = React.lazy(() => import('./pages/WishlistPage')); // Fixed naming

// API & Utilities
import { userAPI } from './api/api';
import toast from 'react-hot-toast';
import './styles/App.css'; // Global app styles

// ========================================
// Utility: Convert URL-safe base64 to ArrayBuffer
// ========================================
const urlBase64ToUint8Array = (base64String) => {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
};

// ========================================
// ProtectedRoute Component
// ========================================
function ProtectedRoute({ children, redirectTo = '/login' }) {
  const { isAuthenticated, loading, user } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="route-loader" aria-live="polite">
        <div className="spinner" role="status">
          <span className="sr-only">Loading...</span>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    // Save the attempted URL for redirecting after login
    return <Navigate to={redirectTo} state={{ from: location }} replace />;
  }

  return children;
}

// ========================================
// Push Notifications Hook (Optimized)
// ========================================
function usePushNotifications() {
  const { user, isAuthenticated } = useAuth();
  const [pushSupported, setPushSupported] = useState(false);
  const [subscription, setSubscription] = useState(null);
  const [permission, setPermission] = useState('default');
  const [isInitializing, setIsInitializing] = useState(true);

  // Check browser support on mount
  useEffect(() => {
    const supported = 
      'serviceWorker' in navigator && 
      'PushManager' in window && 
      'Notification' in window &&
      'IndexedDB' in window;

    setPushSupported(supported);
    if (supported && Notification.permission !== 'default') {
      setPermission(Notification.permission);
    }
    setIsInitializing(false);
  }, []);

  // Load existing subscription from backend on auth change
  useEffect(() => {
    let isMounted = true;

    if (isAuthenticated && user?.id && pushSupported && !isInitializing) {
      loadSubscription();
    }

    return () => { isMounted = false; };
  }, [isAuthenticated, user?.id, pushSupported, isInitializing]);

  const loadSubscription = async () => {
    try {
      const res = await userAPI.getPushSubscription();
      if (res.data?.data?.subscription) {
        setSubscription(res.data.data.subscription);
      }
    } catch (err) {
      if (err.response?.status !== 404) {
        console.warn('Could not load push subscription:', err);
      }
    }
  };

  const registerServiceWorker = useCallback(async () => {
    try {
      const registration = await navigator.serviceWorker.register('/firebase-messaging-sw.js', {
        scope: '/',
        updateViaCache: 'none'
      });
      console.log('✅ Service Worker registered:', registration.scope);
      return registration;
    } catch (err) {
      console.error('❌ Service Worker registration failed:', err);
      throw err;
    }
  }, []);

  const subscribeUserToPush = useCallback(async () => {
    if (!pushSupported) {
      toast.error('Push notifications are not supported in this browser', {
        duration: 4000,
        icon: '⚠️'
      });
      return null;
    }

    try {
      // Request permission
      const permission = await Notification.requestPermission();
      setPermission(permission);

      if (permission !== 'granted') {
        if (permission === 'denied') {
          toast.error('Notifications blocked. Enable in browser settings.', {
            duration: 5000,
            icon: '🔕'
          });
        }
        return null;
      }

      // Register service worker
      const registration = await registerServiceWorker();

      // Get VAPID public key
      const VAPID_PUBLIC_KEY = process.env.REACT_APP_VAPID_PUBLIC_KEY;
      if (!VAPID_PUBLIC_KEY) {
        throw new Error('VAPID_PUBLIC_KEY not configured in environment variables');
      }

      // Subscribe to push
      const pushSubscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY)
      });

      // Send subscription to backend
      const subscriptionData = JSON.parse(JSON.stringify(pushSubscription));
      await userAPI.savePushSubscription({
        endpoint: subscriptionData.endpoint,
        keys: subscriptionData.keys,
        userAgent: navigator.userAgent,
        platform: navigator.platform
      });

      setSubscription(subscriptionData);
      toast.success('🔔 Push notifications enabled!', {
        duration: 3000,
        icon: '✅'
      });
      return subscriptionData;
    } catch (err) {
      console.error('❌ Push subscription failed:', err);
      toast.error('Failed to enable notifications. Please try again.', {
        duration: 4000,
        icon: '❌'
      });
      return null;
    }
  }, [pushSupported, registerServiceWorker]);

  const unsubscribeUser = useCallback(async () => {
    if (!subscription) return;

    try {
      const registration = await navigator.serviceWorker.ready;
      const pushSubscription = await registration.pushManager.getSubscription();

      if (pushSubscription) {
        await pushSubscription.unsubscribe();
      }

      await userAPI.deletePushSubscription();
      setSubscription(null);
      toast.success('Push notifications disabled', {
        duration: 3000,
        icon: '🔕'
      });
    } catch (err) {
      console.error('❌ Unsubscribe failed:', err);
      toast.error('Failed to disable notifications', {
        duration: 4000,
        icon: '❌'
      });
    }
  }, [subscription]);

  // Listen for push messages while app is open (with cleanup)
  useEffect(() => {
    if (!pushSupported || !isAuthenticated) return;

    const handleMessage = (event) => {
      try {
        const data = event.data?.json?.() || event.data;
        console.log('📨 Push message received:', data);

        // Show in-app notification
        if (data?.title || data?.body) {
          toast.custom((t) => (
            <div className={`push-toast ${t.visible ? 'enter' : 'exit'}`} role="alert">
              <div className="push-toast-icon">🔔</div>
              <div className="push-toast-content">
                {data.title && <strong>{data.title}</strong>}
                {data.body && <p>{data.body}</p>}
                {data.url && (
                  <a 
                    href={data.url} 
                    className="toast-action"
                    onClick={() => toast.dismiss(t.id)}
                  >
                    {data.actionText || 'View'} →
                  </a>
                )}
              </div>
            </div>
          ), { 
            duration: 6000,
            position: 'top-right'
          });
        }

        // Trigger data refresh based on notification type
        if (data?.type === 'order_update') {
          // Could dispatch context action here
          console.log('🔄 Order update received - refreshing data...');
        } else if (data?.type === 'price_drop') {
          console.log('📉 Price drop alert received');
        }
      } catch (err) {
        console.error('❌ Error handling push message:', err);
      }
    };

    navigator.serviceWorker?.addEventListener('message', handleMessage);

    return () => {
      navigator.serviceWorker?.removeEventListener('message', handleMessage);
    };
  }, [pushSupported, isAuthenticated]);

  // Cleanup subscription reference on logout (optional)
  useEffect(() => {
    return () => {
      // Keep subscription for re-login experience
      // Uncomment below to auto-unsubscribe on logout:
      // if (!isAuthenticated && subscription) {
      //   unsubscribeUser();
      // }
    };
  }, [isAuthenticated]); // Removed subscription dependency to avoid re-subscribe loops

  return {
    pushSupported,
    permission,
    subscription,
    isInitializing,
    subscribeUserToPush,
    unsubscribeUser,
    refreshPermission: () => setPermission(Notification.permission)
  };
}

// ========================================
// Route Transition Wrapper (Optional Animation)
// ========================================
function AnimatedRoute({ children }) {
  const location = useLocation();

  return (
    <div 
      key={location.pathname}
      className="route-transition"
      style={{ animation: 'fadeIn 0.3s ease-out' }}
    >
      {children}
    </div>
  );
}

// ========================================
// Main App Content
// ========================================
function AppContent() {
  const { isAuthenticated, user, loading: authLoading } = useAuth();
  const { theme } = useTheme();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Initialize push notifications hook ONCE at top level
  const pushNotification = usePushNotifications();
  const { 
    pushSupported, 
    permission, 
    subscription,
    isInitializing: pushInitializing,
    subscribeUserToPush,
    refreshPermission 
  } = pushNotification;

  const location = useLocation();

  // Auto-close sidebar on route change (mobile)
  useEffect(() => {
    if (window.innerWidth < 1024) {
      setSidebarOpen(false);
    }
  }, [location.pathname]);

  // Request push permission hint after login (non-intrusive)
  useEffect(() => {
    if (isAuthenticated && permission === 'default' && pushSupported && !pushInitializing) {
      // Show subtle UI hint instead of auto-requesting
      console.log('💡 Push permission not set - showing UI prompt');
    }
  }, [isAuthenticated, permission, pushSupported, pushInitializing]);

  // Sync permission state when tab becomes visible
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && pushSupported) {
        refreshPermission();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [pushSupported, refreshPermission]);

  // Loading state for initial app boot
  if (authLoading || pushInitializing) {
    return (
      <div className="app-loader" aria-live="polite">
        <div className="loader-content">
          <div className="spinner-lg" role="status">
            <span className="sr-only">Loading application...</span>
          </div>
          <p className="loader-text">Preparing your experience...</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`app-layout ${theme}`}>
      {/* Sidebar for authenticated users */}
      {isAuthenticated && (
        <Sidebar 
          isOpen={sidebarOpen} 
          onClose={() => setSidebarOpen(false)}
          pushPermission={permission}
          onEnablePush={subscribeUserToPush}
          hasActiveSubscription={!!subscription}
        />
      )}

      {/* Main Content Area */}
      <div 
        className="main-content" 
        style={!isAuthenticated ? { marginLeft: 0 } : undefined}
      >
        <Navbar 
          onMenuToggle={() => setSidebarOpen(prev => !prev)}
          pushStatus={{ 
            supported: pushSupported, 
            permission, 
            subscribed: !!subscription,
            onEnable: subscribeUserToPush
          }}
        />

        <main className="page-content" id="main-content" tabIndex="-1">
          <Suspense fallback={
            <div className="page-loader">
              <div className="spinner" role="status">
                <span className="sr-only">Loading page...</span>
              </div>
            </div>
          }>
            <AnimatedRoute>
              <Routes location={location} key={location.pathname}>
                {/* Public Routes */}
                <Route path="/" element={<HomePage />} />
                <Route path="/products" element={<ProductsPage />} />
                <Route path="/products/:id" element={<ProductDetailPage />} />
                <Route path="/tracking" element={<TrackingPage />} />
                <Route path="/login" element={<LoginPage />} />
                <Route path="/register" element={<RegisterPage />} />
                <Route path="/offers" element={<OffersPage />} />

                {/* Protected Routes */}
                <Route path="/price-drop/:id" element={
                  <ProtectedRoute>
                    <PriceDropProductPage />
                  </ProtectedRoute>
                } />
                <Route path="/cart" element={
                  <ProtectedRoute>
                    <CartPage />
                  </ProtectedRoute>
                } />
                <Route path="/checkout" element={
                  <ProtectedRoute>
                    <CheckoutPage />
                  </ProtectedRoute>
                } />
                <Route path="/orders" element={
                  <ProtectedRoute>
                    <OrdersPage />
                  </ProtectedRoute>
                } />
                <Route path="/orders/:id" element={
                  <ProtectedRoute>
                    <OrderDetailPage />
                  </ProtectedRoute>
                } />
                <Route path="/account" element={
                  <ProtectedRoute>
                    <AccountPage />
                  </ProtectedRoute>
                } />
                <Route path="/settings" element={
                  <ProtectedRoute>
                    <SettingsPage 
                      pushProps={{
                        supported: pushSupported,
                        permission,
                        subscribed: !!subscription,
                        onEnable: subscribeUserToPush,
                        onDisable: pushNotification.unsubscribeUser
                      }} 
                    />
                  </ProtectedRoute>
                } />
                <Route path="/wishlist" element={
                  <ProtectedRoute>
                    <WishlistPage />
                  </ProtectedRoute>
                } />
                <Route path="/notifications" element={
                  <ProtectedRoute>
                    <NotificationsPage />
                  </ProtectedRoute>
                } />
                <Route path="/wallet" element={
                  <ProtectedRoute>
                    <WalletPage />
                  </ProtectedRoute>
                } />

                {/* 404 Fallback */}
                <Route path="*" element={
                  <Navigate to="/" state={{ error: 'Page not found' }} replace />
                } />
              </Routes>
            </AnimatedRoute>
          </Suspense>
        </main>

        {/* Global Chat Widget */}
        <ChatWidget />
      </div>

      {/* Non-intrusive Push Permission Banner */}
      {isAuthenticated && 
       pushSupported && 
       permission === 'default' && 
       !subscription && 
       !pushInitializing && (
        <div className="push-permission-banner" role="complementary" aria-label="Enable notifications">
          <div className="banner-icon">🔔</div>
          <div className="banner-content">
            <strong>Get instant updates</strong>
            <p>Enable push for orders, price drops & security alerts</p>
          </div>
          <div className="banner-actions">
            <button 
              className="btn btn-sm btn-ghost"
              onClick={() => {
                // Dismiss banner (could save preference to localStorage)
                document.querySelector('.push-permission-banner')?.remove();
              }}
              aria-label="Maybe later"
            >
              Later
            </button>
            <button 
              className="btn btn-sm btn-primary"
              onClick={subscribeUserToPush}
              aria-label="Enable push notifications"
            >
              Enable
            </button>
          </div>
        </div>
      )}

      {/* Skip to Content Link (Accessibility) */}
      <a href="#main-content" className="skip-link">
        Skip to main content
      </a>
    </div>
  );
}

